    int h = seed ^ length;

    final int nblocks = length >> 2;

    for (int i = 0; i < nblocks; i++) {
        final int index = (i << 2);
        int k = getLittleEndianInt(data, index);
        k *= M32;
        k ^= k >>> R32;
        k *= M32;
        h *= M32;
        h ^= k;
    }

    final int index = (nblocks << 2);
    switch (length - index) {
        case 3:
            h ^= (data[index + 2] & 0xff) << 16;
        case 2:
            h ^= (data[index + 1] & 0xff) << 8;
        case 1:
            h ^= (data[index] & 0xff);
            h *= M32;
    }

    h ^= h >>> 13;
    h *= M32;
    h ^= h >>> 15;

    return h;
}

